mapper.update:
MERGE  STOCCUDM  A
USING (SELECT #{ses.gateCd} AS GATE_CD
            , #{CUST_CD} AS CUST_CD
            , #{USER_ID} AS USER_ID

            ,(#{SEQ}, '999') AS SEQ


            , CONVERT(INT, (#{SEQ}, '999')) AS SEQ


        ) B
    ON (A.GATE_CD = B.GATE_CD
    AND A.CUST_CD = B.CUST_CD
    AND A.USER_ID  = B.USER_ID
    AND A.SEQ = B.SEQ)
WHEN MATCHED THEN
UPDATE SET
      DELY_NM = #{DELY_NM}
    , RECIPIENT_NM = #{RECIPIENT_NM}
    , RECIPIENT_DEPT_NM = #{RECIPIENT_DEPT_NM}
    , RECIPIENT_TEL_NUM = #{RECIPIENT_TEL_NUM}
    , RECIPIENT_CELL_NUM = #{RECIPIENT_CELL_NUM}
    , RECIPIENT_EMAIL = #{RECIPIENT_EMAIL}
    , DELY_ZIP_CD = #{DELY_ZIP_CD}
    , DELY_ADDR_1 = #{DELY_ADDR_1}
    , DELY_ADDR_2 = #{DELY_ADDR_2}
    , DELY_RMK = #{DELY_RMK}
    , MOD_DATE = SYSDATE
    , MOD_USER_ID =  #{ses.userId}
WHEN NOT MATCHED THEN
INSERT (
      GATE_CD
    , CUST_CD
    , USER_ID
    , SEQ
    , REG_DATE
    , REG_USER_ID
    , MOD_DATE
    , MOD_USER_ID
    , DEL_FLAG
    , DELY_NM
    , RECIPIENT_NM
    , RECIPIENT_DEPT_NM
    , RECIPIENT_TEL_NUM
    , RECIPIENT_CELL_NUM
    , RECIPIENT_EMAIL
    , DELY_ZIP_CD
    , DELY_ADDR_1
    , DELY_ADDR_2
    , DELY_RMK
) VALUES (
      #{ses.gateCd}
    , #{CUST_CD}
    , #{USER_ID}
    , (SELECT (MAX(SEQ) + 1, 1) FROM STOCCUDM WHERE GATE_CD = #{ses.gateCd} AND CUST_CD = #{CUST_CD} AND USER_ID = #{USER_ID})
    , SYSDATE
    , #{ses.userId}
    , SYSDATE
    , #{ses.userId}
    , '0'
    , #{DELY_NM}
    , #{RECIPIENT_NM}
    , #{RECIPIENT_DEPT_NM}
    , #{RECIPIENT_TEL_NUM}
    , #{RECIPIENT_CELL_NUM}
    , #{RECIPIENT_EMAIL}
    , #{DELY_ZIP_CD}
    , #{DELY_ADDR_1}
    , #{DELY_ADDR_2}
    , #{DELY_RMK}
)

UPDATE STOCCUDM SET
      DEL_FLAG = '1'
    , MOD_DATE = SYSDATE
    , MOD_USER_ID = #{ses.userId}
 WHERE GATE_CD = #{ses.gateCd}
   AND CUST_CD = #{CUST_CD}
   AND USER_ID = #{USER_ID}
   AND SEQ = #{SEQ}

